import{_ as e,c as i,o as r,a1 as a}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"릴리스 노트: 버전 히스토리 및 기능 변경 | Agent App Factory","description":"Agent App Factory의 버전 업데이트 히스토리, 기능 변경 사항, 버그 수정 및 주요 개선 사항을 확인하세요. 이 페이지는 1.0.0 버전부터 시작하는 완전한 변경 히스토리를 자세히 기록하며, 7단계 파이프라인 시스템, Sisyphus 스케줄러, 권한 관리, 컨텍스트 최적화 및 실패 처리 전략 등 핵심 기능과 개선 사항을 포함합니다.","frontmatter":{"title":"릴리스 노트: 버전 히스토리 및 기능 변경 | Agent App Factory","sidebarTitle":"릴리스 노트","subtitle":"릴리스 노트: 버전 히스토리 및 기능 변경 | Agent App Factory","description":"Agent App Factory의 버전 업데이트 히스토리, 기능 변경 사항, 버그 수정 및 주요 개선 사항을 확인하세요. 이 페이지는 1.0.0 버전부터 시작하는 완전한 변경 히스토리를 자세히 기록하며, 7단계 파이프라인 시스템, Sisyphus 스케줄러, 권한 관리, 컨텍스트 최적화 및 실패 처리 전략 등 핵심 기능과 개선 사항을 포함합니다.","tags":["릴리스 노트","버전 히스토리"],"prerequisite":[],"order":250},"headers":[],"relativePath":"ko/hyz1992/agent-app-factory/changelog/release-notes/index.md","filePath":"ko/hyz1992/agent-app-factory/changelog/release-notes/index.md"}'),l={name:"ko/hyz1992/agent-app-factory/changelog/release-notes/index.md"};function o(n,t,d,c,s,p){return r(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="릴리스-노트" tabindex="-1">릴리스 노트 <a class="header-anchor" href="#릴리스-노트" aria-label="Permalink to &quot;릴리스 노트&quot;">​</a></h1><p>이 페이지는 Agent App Factory의 버전 업데이트 히스토리를 기록하며, 새로운 기능, 개선 사항, 버그 수정 및 호환성에 영향을 미치는 변경 사항을 포함합니다.</p><p>형식은 <a href="https://keepachangelog.com/ko/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a> 규격을 따르며, 버전 번호는 <a href="https://semver.org/lang/ko/" target="_blank" rel="noreferrer">Semantic Versioning</a>을 따릅니다.</p><h2 id="_1-0-0-2024-01-29" tabindex="-1">[1.0.0] - 2024-01-29 <a class="header-anchor" href="#_1-0-0-2024-01-29" aria-label="Permalink to &quot;[1.0.0] - 2024-01-29&quot;">​</a></h2><h3 id="추가됨" tabindex="-1">추가됨 <a class="header-anchor" href="#추가됨" aria-label="Permalink to &quot;추가됨&quot;">​</a></h3><p><strong>핵심 기능</strong></p><ul><li><p><strong>7단계 파이프라인 시스템</strong>: 아이디어에서 실행 가능한 애플리케이션까지의 완전한 자동화 프로세스</p><ul><li>Bootstrap - 제품 아이디어 구조화 (input/idea.md)</li><li>PRD - 제품 요구사항 문서 생성 (artifacts/prd/prd.md)</li><li>UI - UI 구조 및 미리보기 가능한 프로토타입 설계 (artifacts/ui/)</li><li>Tech - 기술 아키텍처 및 Prisma 데이터 모델 설계 (artifacts/tech/)</li><li>Code - 프론트엔드 및 백엔드 코드 생성 (artifacts/backend/, artifacts/client/)</li><li>Validation - 코드 품질 검증 (artifacts/validation/report.md)</li><li>Preview - 배포 가이드 생성 (artifacts/preview/README.md)</li></ul></li><li><p><strong>Sisyphus 스케줄러</strong>: 파이프라인의 핵심 제어 컴포넌트</p><ul><li>pipeline.yaml에 정의된 각 Stage를 순서대로 실행</li><li>각 단계의 입력/출력 및 종료 조건 검증</li><li>파이프라인 상태 유지 (.factory/state.json)</li><li>권한 검사 수행, Agent의 권한 초과 접근 방지</li><li>실패 전략에 따른 예외 상황 처리</li><li>각 체크포인트에서 일시 중지, 수동 확인 후 계속</li></ul></li></ul><p><strong>CLI 도구</strong></p><ul><li><code>factory init</code> - Factory 프로젝트 초기화</li><li><code>factory run [stage]</code> - 파이프라인 실행 (현재 또는 지정된 단계부터)</li><li><code>factory continue</code> - 새 세션에서 실행 계속 (토큰 절약)</li><li><code>factory status</code> - 현재 프로젝트 상태 확인</li><li><code>factory list</code> - 모든 Factory 프로젝트 나열</li><li><code>factory reset</code> - 현재 프로젝트 상태 초기화</li></ul><p><strong>권한 및 보안</strong></p><ul><li><strong>능력 경계 매트릭스</strong> (capability.matrix.md): 각 Agent의 엄격한 읽기/쓰기 권한 정의 <ul><li>각 Agent는 승인된 디렉토리만 접근 가능</li><li>권한 초과 파일 쓰기 시 artifacts/_untrusted/로 이동</li><li>실패 후 파이프라인 자동 일시 중지, 수동 개입 대기</li></ul></li></ul><p><strong>컨텍스트 최적화</strong></p><ul><li><strong>분기 실행</strong>: 각 단계를 새 세션에서 실행 <ul><li>컨텍스트 누적 방지, 토큰 절약</li><li>중단 및 복구 지원</li><li>모든 AI 어시스턴트(Claude Code, OpenCode, Cursor)에 적용 가능</li></ul></li></ul><p><strong>실패 처리 전략</strong></p><ul><li>자동 재시도 메커니즘: 각 단계당 한 번 재시도 허용</li><li>실패 보관: 실패한 산출물을 artifacts/_failed/로 이동</li><li>롤백 메커니즘: 최근 성공 체크포인트로 롤백</li><li>수동 개입: 연속 두 번 실패 후 일시 중지</li></ul><p><strong>품질 보장</strong></p><ul><li><p><strong>코드 규격</strong> (code-standards.md)</p><ul><li>TypeScript 코딩 규격 및 모범 사례</li><li>파일 구조 및 명명 규칙</li><li>주석 및 문서화 요구 사항</li><li>Git 커밋 메시지 규격(Conventional Commits)</li></ul></li><li><p><strong>에러 코드 규격</strong> (error-codes.md)</p><ul><li>통일된 에러 코드 구조: [MODULE]<em>[ERROR_TYPE]</em>[SPECIFIC]</li><li>표준 에러 유형: VALIDATION, NOT_FOUND, FORBIDDEN, CONFLICT, INTERNAL_ERROR</li><li>프론트엔드 및 백엔드 에러 코드 매핑 및 사용자 친화적 안내</li></ul></li></ul><p><strong>Changelog 관리</strong></p><ul><li>Keep a Changelog 형식 준수</li><li>Conventional Commits와 통합</li><li>자동화 도구 지원: conventional-changelog-cli, release-it</li></ul><p><strong>구성 템플릿</strong></p><ul><li>CI/CD 구성(GitHub Actions)</li><li>Git Hooks 구성(Husky)</li></ul><p><strong>생성된 애플리케이션 특성</strong></p><ul><li>완전한 프론트엔드 및 백엔드 코드(Express + Prisma + React Native)</li><li>단위 테스트 및 통합 테스트(Vitest + Jest)</li><li>API 문서(Swagger/OpenAPI)</li><li>데이터베이스 시드 데이터</li><li>Docker 배포 구성</li><li>에러 처리 및 로그 모니터링</li><li>성능 최적화 및 보안 검사</li></ul><h3 id="개선됨" tabindex="-1">개선됨 <a class="header-anchor" href="#개선됨" aria-label="Permalink to &quot;개선됨&quot;">​</a></h3><p><strong>MVP 집중</strong></p><ul><li>비목표(Non-Goals)를 명확히 나열하여 범위 확장 방지</li><li>페이지 수를 3페이지 이내로 제한</li><li>핵심 기능에 집중, 과도한 설계 방지</li></ul><p><strong>책임 분리</strong></p><ul><li>각 Agent는 자신의 영역만 담당하며 영역을 넘지 않음</li><li>PRD는 기술 세부 사항을 포함하지 않으며, Tech는 UI 설계에 관여하지 않음</li><li>Code Agent는 UI Schema와 Tech 설계를 엄격히 구현</li></ul><p><strong>검증 가능성</strong></p><ul><li>각 단계에서 명확한 exit_criteria 정의</li><li>모든 기능이 테스트 가능하며 로컬에서 실행 가능</li><li>산출물은 반드시 구조화되어 있어 다운스트림에서 사용 가능</li></ul><h3 id="기술-스택" tabindex="-1">기술 스택 <a class="header-anchor" href="#기술-스택" aria-label="Permalink to &quot;기술 스택&quot;">​</a></h3><p><strong>CLI 도구</strong></p><ul><li>Node.js &gt;= 16.0.0</li><li>Commander.js - 명령줄 프레임워크</li><li>Chalk - 컬러 터미널 출력</li><li>Ora - 진행 표시기</li><li>Inquirer - 대화형 명령줄</li><li>fs-extra - 파일 시스템 작업</li><li>YAML - YAML 파싱</li></ul><p><strong>생성된 애플리케이션</strong></p><ul><li>백엔드: Node.js + Express + Prisma + TypeScript + Vitest</li><li>프론트엔드: React Native + Expo + TypeScript + Jest + React Testing Library</li><li>배포: Docker + GitHub Actions</li></ul><h3 id="의존성" tabindex="-1">의존성 <a class="header-anchor" href="#의존성" aria-label="Permalink to &quot;의존성&quot;">​</a></h3><ul><li><code>chalk@^4.1.2</code> - 터미널 색상 스타일</li><li><code>commander@^11.0.0</code> - 명령줄 인자 파싱</li><li><code>fs-extra@^11.1.1</code> - 파일 시스템 확장</li><li><code>inquirer@^8.2.5</code> - 대화형 명령줄</li><li><code>ora@^5.4.1</code> - 우아한 터미널 로더</li><li><code>yaml@^2.3.4</code> - YAML 파싱 및 직렬화</li></ul><h2 id="버전-설명" tabindex="-1">버전 설명 <a class="header-anchor" href="#버전-설명" aria-label="Permalink to &quot;버전 설명&quot;">​</a></h2><h3 id="semantic-versioning" tabindex="-1">Semantic Versioning <a class="header-anchor" href="#semantic-versioning" aria-label="Permalink to &quot;Semantic Versioning&quot;">​</a></h3><p>이 프로젝트는 <a href="https://semver.org/lang/ko/" target="_blank" rel="noreferrer">Semantic Versioning</a> 버전 번호 형식을 따릅니다: MAJOR.MINOR.PATCH</p><ul><li><strong>MAJOR</strong>: 하위 호환되지 않는 API 변경</li><li><strong>MINOR</strong>: 하위 호환되는 새로운 기능</li><li><strong>PATCH</strong>: 하위 호환되는 버그 수정</li></ul><h3 id="변경-유형" tabindex="-1">변경 유형 <a class="header-anchor" href="#변경-유형" aria-label="Permalink to &quot;변경 유형&quot;">​</a></h3><ul><li><strong>추가됨</strong> (Added): 새로운 기능</li><li><strong>변경됨</strong> (Changed): 기존 기능의 변경</li><li><strong>사용 중단</strong> (Deprecated): 곧 제거될 기능</li><li><strong>제거됨</strong> (Removed): 제거된 기능</li><li><strong>수정됨</strong> (Fixed): 버그 수정</li><li><strong>보안</strong> (Security): 보안 수정</li></ul><h2 id="관련-자료" tabindex="-1">관련 자료 <a class="header-anchor" href="#관련-자료" aria-label="Permalink to &quot;관련 자료&quot;">​</a></h2><ul><li><a href="https://github.com/hyz1992/agent-app-factory/releases" target="_blank" rel="noreferrer">GitHub 릴리스</a> - 공식 릴리스 페이지</li><li><a href="https://github.com/hyz1992/agent-app-factory" target="_blank" rel="noreferrer">프로젝트 저장소</a> - 소스 코드</li><li><a href="https://github.com/hyz1992/agent-app-factory/issues" target="_blank" rel="noreferrer">이슈 트래커</a> - 문제 및 제안 피드백</li><li><a href="https://github.com/hyz1992/agent-app-factory/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">기여 가이드</a> - 기여 방법</li></ul><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 보기</strong></summary><blockquote><p>업데이트 시간: 2024-01-29</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>라인 번호</th></tr></thead><tbody><tr><td>package.json</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/package.json" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-52</td></tr><tr><td>CLI 진입점</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/bin/factory.js" target="_blank" rel="noreferrer"><code>cli/bin/factory.js</code></a></td><td>1-123</td></tr><tr><td>초기화 명령</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/init.js" target="_blank" rel="noreferrer"><code>cli/commands/init.js</code></a></td><td>1-427</td></tr><tr><td>실행 명령</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/run.js" target="_blank" rel="noreferrer"><code>cli/commands/run.js</code></a></td><td>1-294</td></tr><tr><td>계속 명령</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/cli/commands/continue.js" target="_blank" rel="noreferrer"><code>cli/commands/continue.js</code></a></td><td>1-87</td></tr><tr><td>파이프라인 정의</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/pipeline.yaml" target="_blank" rel="noreferrer"><code>pipeline.yaml</code></a></td><td>1-87</td></tr><tr><td>스케줄러 정의</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/agents/orchestrator.checkpoint.md" target="_blank" rel="noreferrer"><code>agents/orchestrator.checkpoint.md</code></a></td><td>1-301</td></tr><tr><td>권한 매트릭스</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/capability.matrix.md" target="_blank" rel="noreferrer"><code>policies/capability.matrix.md</code></a></td><td>1-44</td></tr><tr><td>실패 정책</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/failure.policy.md" target="_blank" rel="noreferrer"><code>policies/failure.policy.md</code></a></td><td>1-200</td></tr><tr><td>코드 규격</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/code-standards.md" target="_blank" rel="noreferrer"><code>policies/code-standards.md</code></a></td><td>1-287</td></tr><tr><td>에러 코드 규격</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/error-codes.md" target="_blank" rel="noreferrer"><code>policies/error-codes.md</code></a></td><td>1-134</td></tr><tr><td>Changelog 규격</td><td><a href="https://github.com/hyz1992/agent-app-factory/blob/main/policies/changelog.md" target="_blank" rel="noreferrer"><code>policies/changelog.md</code></a></td><td>1-87</td></tr></tbody></table><p><strong>주요 버전 정보</strong>:</p><ul><li><code>version = &quot;1.0.0&quot;</code>: 초기 릴리스 버전</li><li><code>engines.node = &quot;&gt;=16.0.0&quot;</code>: 최소 Node.js 버전 요구사항</li></ul><p><strong>의존성 버전</strong>:</p><ul><li><code>chalk@^4.1.2</code>: 터미널 색상 스타일</li><li><code>commander@^11.0.0</code>: 명령줄 인자 파싱</li><li><code>fs-extra@^11.1.1</code>: 파일 시스템 확장</li><li><code>inquirer@^8.2.5</code>: 대화형 명령줄</li><li><code>ora@^5.4.1</code>: 우아한 터미널 로더</li><li><code>yaml@^2.3.4</code>: YAML 파싱 및 직렬화</li></ul></details>',48)])])}const u=e(l,[["render",o]]);export{h as __pageData,u as default};
